sq.example:
object Hello {
  def main(args: Array[String]): Unit = {
    println("Hello, World!")

    val emri = "Ardian"
    println(s"Miresevini, $emri!")

    // Functional
    val numrat = List(1, 2, 3, 4, 5)
    val shuma = numrat.reduce(_ + _)
    println(s"Shuma: $shuma")
  }
}

